import java.io.*;
import java.util.*;

public class Main {
    static int height(int node, int[] left, int[] right) {
        if (node == 0) return -1; // null child contributes -1 so leaf becomes 0
        int lh = height(left[node], left, right);
        int rh = height(right[node], left, right);
        return Math.max(lh, rh) + 1;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        String line = br.readLine();
        if (line == null) return;
        line = line.trim();
        if (line.isEmpty()) return;
        int T = Integer.parseInt(line);
        for (int t = 0; t < T; t++) {
            // read N, skipping possible empty lines
            String nLine;
            while (true) {
                nLine = br.readLine();
                if (nLine == null) break; // EOF reached unexpectedly
                nLine = nLine.trim();
                if (!nLine.isEmpty()) break;
            }
            if (nLine == null) break; // no more test cases
            int N = Integer.parseInt(nLine);
            int[] left = new int[N + 1];
            int[] right = new int[N + 1];
            for (int i = 0; i < N - 1; i++) {
                String edgeLine = br.readLine();
                while (edgeLine != null && edgeLine.trim().isEmpty()) {
                    edgeLine = br.readLine();
                }
                if (edgeLine == null) break; // safety, though input should be correct
                StringTokenizer st = new StringTokenizer(edgeLine);
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                if (dir == 'L') left[p] = c; else right[p] = c;
            }
            sb.append(height(1, left, right));
            if (t != T - 1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

